// ── STOP THE BLEED ─────────────────────────────────────────────────────
window.QB_STOP_BLEED = {
flashcards:{
easy:[
  {term:"Stop the Bleed program",def:"National campaign teaching civilians to control life-threatening bleeding before EMS arrives",breakdown:"Launched 2015 after Sandy Hook. Based on military lessons from battlefield medicine"},
  {term:"Call 911 first",def:"Always call 911 FIRST before treating a bleeding victim — activates EMS response",breakdown:"Dispatcher can guide you while help is coming. Give location, what happened, how many injured"},
  {term:"3 steps: Call, Compress, Tourniquet",def:"Call 911 → Apply pressure → Use tourniquet if needed. The core Stop the Bleed sequence",breakdown:"Life-threatening limb bleeding kills in 3-5 minutes. These steps buy time until EMS arrives"},
  {term:"Direct pressure",def:"Pressing firmly and continuously on a wound with hands or cloth to slow/stop bleeding",breakdown:"First and most important step. Use gloves if available. Never remove a soaked dressing — add more on top"},
  {term:"Wound packing",def:"Pushing gauze or cloth DEEPLY into a wound and pressing hard to control bleeding",breakdown:"Used for deep wounds where surface pressure is not enough. Pack tightly, then apply firm pressure"},
  {term:"Tourniquet",def:"A tight band placed above a wound on a limb to stop blood flow and control life-threatening bleeding",breakdown:"Apply 2-3 inches above the wound. Tighten until bleeding stops. Note the time applied"},
  {term:"Junctional wound",def:"Bleeding wound at the junction of the limb and torso — groin, armpit, neck — cannot use tourniquet",breakdown:"Use wound packing + direct pressure for junctional wounds. Cannot apply tourniquet here"},
  {term:"Commercial tourniquet (CAT)",def:"Combat Application Tourniquet — most widely used device. Self-applicable with one hand",breakdown:"Preferred over improvised tourniquets. Available in Stop the Bleed kits and first aid kits"},
  {term:"Hemostatic gauze",def:"Gauze treated with a clotting agent (Combat Gauze/QuikClot) that dramatically accelerates clotting",breakdown:"Used in wound packing for severe bleeding. Press firmly for 3+ minutes after packing"},
  {term:"Pressure dressing",def:"A bandage applied firmly over a wound to maintain direct pressure after controlling bleeding",breakdown:"Wrap snugly, not too tight. Prevents dressing from shifting. Secure with tape or knot"},
  {term:"Life-threatening bleeding signs",def:"Blood spurting from wound, blood soaking through clothing rapidly, blood pooling on ground",breakdown:"Any of these = immediate action required. Hesitation costs lives — act within seconds"},
  {term:"Time to exsanguination",def:"Uncontrolled limb bleeding can cause death from blood loss in as little as 3-5 minutes",breakdown:"This is why Stop the Bleed training targets civilian bystanders — EMS takes longer to arrive"},
  {term:"Tourniquet time documentation",def:"Always write the time tourniquet was applied on the band or patients skin (e.g. TK 14:32)",breakdown:"Hospital teams need to know how long it has been on to plan vascular surgery"},
  {term:"Never remove a tourniquet",def:"Once a tourniquet is applied for life-threatening bleeding, ONLY remove it in a hospital setting",breakdown:"Removal in the field causes rapid hemorrhage. 'Tourniquet on = leave it on' until definitive care"},
  {term:"PPE (gloves)",def:"Personal Protective Equipment — wear gloves when possible to protect yourself from bloodborne pathogens",breakdown:"Nitrile gloves in every Stop the Bleed kit. If no gloves, use plastic bag or extra cloth as barrier"},
],
medium:[
  {term:"Arterial vs venous bleeding",def:"Arterial: bright red, spurting with each heartbeat. Venous: dark red, steady flow. Both can be fatal",breakdown:"Arterial bleeding is more immediately life-threatening due to pressure. Both require immediate control"},
  {term:"Hemorrhagic shock",def:"Life-threatening condition from massive blood loss — body cannot maintain organ perfusion",breakdown:"Class I-IV. Class III-IV require immediate tourniquet/packing + 911. Signs: pale, cold, confused"},
  {term:"Tourniquet width",def:"Must be at least 1.5-2 inches wide to be effective. Narrow bands cut skin without stopping bleeding",breakdown:"Standard CAT tourniquet = 1.5 inches wide. Never use wire, rope, or string — too narrow"},
  {term:"Two-tourniquet technique",def:"Two tourniquets applied when one does not fully control bleeding or wound is very proximal (high on limb)",breakdown:"Apply second tourniquet immediately above first. Used when first TK fails to stop bleeding"},
  {term:"Wound packing technique",def:"1) Apply pressure, 2) Identify bleeding point, 3) Pack gauze tightly into wound, 4) Apply firm pressure 3+ min",breakdown:"Use entire piece of gauze. Pack against the bleeding point, not just filling the wound cavity"},
  {term:"Recovery position after bleeding controlled",def:"Once bleeding controlled, keep patient warm, calm, lying flat (elevate legs if no spinal injury)",breakdown:"Shock position — legs elevated helps blood return to vital organs. Keep warm to prevent hypothermia"},
  {term:"Bystander CPR and bleed analogy",def:"Just as CPR training empowers bystanders to respond to cardiac arrest, Stop the Bleed trains bystanders for hemorrhage",breakdown:"Research shows 80% of trauma deaths occur before hospital — bystanders are true first responders"},
  {term:"Improvised tourniquet",def:"If no commercial tourniquet: wide cloth (shirt, belt), apply above wound, twist stick/rod until bleeding stops, secure",breakdown:"Not as reliable as commercial TK but better than nothing. Must be wide (2+ inches) and very tight"},
  {term:"Neck wound treatment",def:"Neck wounds cannot use tourniquet. Apply FIRM direct pressure with palm. Do not compress both sides simultaneously",breakdown:"Compressing both carotid arteries simultaneously stops blood flow to brain. Use one-sided pressure"},
  {term:"Stop the Bleed kit contents",def:"Tourniquet (CAT), hemostatic gauze, pressure bandage, gloves, trauma shears, permanent marker",breakdown:"Bleeding control kits now in schools, airports, sports venues. Know where yours is located"},
],
hard:[
  {term:"Topical hemostatic agents mechanism",def:"Kaolin (Combat Gauze) or zeolite (QuikClot) activate the clotting cascade, concentrating clotting factors",breakdown:"Applied with direct pressure for minimum 3 minutes. Kaolin-based preferred — does not generate heat"},
  {term:"MARCH protocol",def:"Massive hemorrhage → Airway → Respiration → Circulation → Hypothermia: TCCC (Tactical Combat Casualty Care) sequence",breakdown:"Differs from civilian ABCDE — massive hemorrhage moved to #1 priority based on battlefield experience"},
  {term:"Permissive hypotension",def:"Allowing lower-than-normal BP during hemorrhage control — prevents 'popping the clot' before surgery",breakdown:"Systolic 80-90 mmHg target in penetrating trauma. Different from civilian trauma management"},
  {term:"Damage control resuscitation",def:"Early use of blood products (1:1:1 ratio — RBC:plasma:platelets) rather than crystalloid fluids",breakdown:"Prevents the 'lethal triad': hypothermia, acidosis, coagulopathy that kills trauma patients"},
  {term:"Lethal triad of trauma",def:"Hypothermia + Acidosis + Coagulopathy — three conditions that create a deadly feedback loop in trauma",breakdown:"Each worsens the others. Prevention: control bleeding fast, keep patient warm, limit IV crystalloids"},
]},
quiz:{
easy:[
  {q:"What is the FIRST step in the Stop the Bleed sequence?",opts:["Apply a tourniquet","Pack the wound","Call 911","Put on gloves"],correct:2,explain:"Call 911 FIRST — always. This activates the EMS response. The dispatcher can guide you while you treat the patient. Then: compress the wound, and use a tourniquet if needed."},
  {q:"For a wound where blood is soaking through clothing rapidly, your FIRST action is:",opts:["Apply a tourniquet immediately","Call 911, then apply firm direct pressure","Remove clothing to see wound","Give the patient water"],correct:1,explain:"Call 911 first, then apply firm direct pressure. Direct pressure is always the first bleeding control step. Tourniquet is used when direct pressure fails or for massive arterial bleeding on a limb."},
  {q:"A tourniquet should be placed:",opts:["Directly over the wound","2-3 inches BELOW the wound","2-3 inches ABOVE (proximal to) the wound","Only if blood is bright red"],correct:2,explain:"Tourniquet goes 2-3 inches ABOVE (proximal to = closer to the heart) the wound. This compresses the artery supplying the wound. Note the time of application."},
  {q:"After applying a tourniquet, you should:",opts:["Remove it after 10 minutes","Loosen it periodically to restore circulation","Write the time of application and leave it on","Never apply a second one"],correct:2,explain:"Write the application time on the tourniquet or skin (e.g., 'TK 14:32'). Never remove a tourniquet in the field — only hospital staff should remove it. Releasing it causes rapid re-bleeding."},
  {q:"Wound packing is used for:",opts:["Surface scratches","Deep wounds where direct surface pressure cannot reach the bleeding point","All wounds equally","Only head wounds"],correct:1,explain:"Wound packing is for deep wounds — penetrating injuries to the torso, junctional areas, or deep lacerations — where surface pressure cannot reach the bleeding point. Pack gauze tightly against the bleeding source."},
  {q:"Junctional wounds (groin, armpit) cannot use a tourniquet because:",opts:["Tourniquets are only for arms","You cannot get a tourniquet above these wounds — they are at the body-limb junction","Junctional wounds do not bleed severely","Tourniquets damage these areas too much"],correct:1,explain:"Junctional areas are where the limb meets the torso — you cannot place a tourniquet proximal to (above) these wounds. Use wound packing + firm direct pressure instead."},
  {q:"The #1 reason civilian Stop the Bleed training is critical is:",opts:["Ambulances take too long to arrive — bystanders can act in the first critical minutes","Hospitals are too expensive","Police cannot help","Doctors are always nearby"],correct:0,explain:"Uncontrolled hemorrhage kills in 3-5 minutes. EMS response times average 7-10 minutes in urban areas, longer in rural. Trained bystanders acting in the first 1-2 minutes save lives that EMS cannot."},
  {q:"If blood soaks through a dressing, you should:",opts:["Remove the soaked dressing and replace it","Add more dressing on top without removing the first","Apply a tourniquet immediately","Stop applying pressure"],correct:1,explain:"NEVER remove a soaked dressing — it disrupts clot formation. Add more dressing material on top and continue firm direct pressure. Only switch to tourniquet if massive limb bleeding is not controlled."},
],
medium:[
  {q:"Arterial bleeding is recognized by:",opts:["Dark red blood flowing steadily","Bright red blood spurting with each heartbeat","Slow oozing from the wound surface","Brown-tinged blood"],correct:1,explain:"Arteries carry oxygenated blood under high pressure from the heart. Arterial bleeding = bright red (oxygenated) and spurts with each heartbeat (due to cardiac pressure). Most life-threatening type — can exsanguinate in minutes."},
  {q:"The Stop the Bleed program was inspired by lessons from:",opts:["Natural disaster response","Battlefield medicine (military combat experience)","Hospital emergency departments","Medical schools"],correct:1,explain:"Stop the Bleed was developed using lessons from military combat casualty care (TCCC) — the military found that training soldiers and bystanders to control hemorrhage dramatically reduced preventable combat deaths."},
  {q:"A commercially available Stop the Bleed kit should contain:",opts:["AED, CPR mask, gloves","Tourniquet, hemostatic gauze, pressure bandage, gloves","Only sterile gauze and tape","Epinephrine auto-injector"],correct:1,explain:"Standard Stop the Bleed / bleeding control kit: tourniquet (CAT), hemostatic gauze (Combat Gauze), pressure bandage, nitrile gloves, trauma shears, and a permanent marker for writing tourniquet time."},
  {q:"Why should improvised tourniquets (cloth strips, belts) be wide?",opts:["To be more comfortable","Narrow bands cut into skin without compressing the artery effectively","Wide tourniquets are easier to tie","Width does not matter — only tightness matters"],correct:1,explain:"A tourniquet must compress the artery, not just the skin. Narrow bands (wire, cord, string) cut deeply into tissue WITHOUT compressing the underlying artery, causing tissue damage without stopping bleeding. Minimum width: 1.5-2 inches."},
]
}
}; // end QB_STOP_BLEED

// ── VETERINARY SCIENCE ──────────────────────────────────────────────────
window.QB_VETERINARY = {
flashcards:{
easy:[
  {term:"Veterinary medicine",def:"Medical science devoted to preventing, diagnosing, and treating diseases in animals",breakdown:"Veterinarians (DVMs) care for companion animals, livestock, wildlife, zoo animals, and public health"},
  {term:"Companion animals",def:"Animals kept primarily for companionship: dogs, cats, rabbits, guinea pigs, birds, fish, reptiles",breakdown:"Also called pets. Most common in vet practice. Dogs and cats account for ~80% of vet visits"},
  {term:"Canine",def:"Pertaining to dogs (Canis lupus familiaris)",breakdown:"From Latin canis = dog. Canine teeth, canine distemper, canine parvovirus"},
  {term:"Feline",def:"Pertaining to cats (Felis catus)",breakdown:"From Latin felis = cat. Feline leukemia, feline calicivirus, feline panleukopenia"},
  {term:"Avian",def:"Pertaining to birds",breakdown:"From Latin avis = bird. Avian influenza, avian veterinarian, avian anatomy"},
  {term:"Equine",def:"Pertaining to horses (Equus caballus)",breakdown:"From Latin equus = horse. Equine veterinarian, equine colic, equine influenza"},
  {term:"Bovine",def:"Pertaining to cattle (Bos taurus)",breakdown:"From Latin bos = ox/cattle. Bovine spongiform encephalopathy (mad cow disease)"},
  {term:"Porcine",def:"Pertaining to pigs (Sus scrofa domesticus)",breakdown:"From Latin porcus = pig. Porcine reproductive and respiratory syndrome (PRRS)"},
  {term:"Ovine",def:"Pertaining to sheep (Ovis aries)",breakdown:"From Latin ovis = sheep. Ovine progressive pneumonia, ovine johnes disease"},
  {term:"Caprine",def:"Pertaining to goats (Capra aegagrus hircus)",breakdown:"From Latin capra = goat. Caprine arthritis encephalitis (CAE) virus"},
  {term:"DVM degree",def:"Doctor of Veterinary Medicine — the professional degree required to practice veterinary medicine",breakdown:"4 years of vet school after undergraduate degree. Similar length to MD training"},
  {term:"Zoonosis",def:"Disease that can be transmitted between animals and humans",breakdown:"Examples: rabies, toxoplasmosis, Lyme disease, salmonella, MRSA, COVID-19. Critical public health concern"},
  {term:"Rabies",def:"Fatal viral zoonotic disease affecting the nervous system; transmitted through infected saliva (bites)",breakdown:"Almost always fatal once symptoms appear. Preventable by vaccination. All dogs/cats should be vaccinated"},
  {term:"Vaccination schedule (dog)",def:"Core vaccines: Rabies, DHPP (Distemper/Hepatitis/Parvovirus/Parainfluenza) at 8, 12, 16 weeks then annually",breakdown:"Non-core (lifestyle): Bordetella (kennel cough), Lyme, Leptospirosis, Influenza"},
  {term:"Vaccination schedule (cat)",def:"Core vaccines: Rabies, FVRCP (Feline Viral Rhinotracheitis/Calicivirus/Panleukopenia)",breakdown:"Non-core: FeLV (feline leukemia) for outdoor cats. Indoor cats at lower risk"},
  {term:"Spay (ovariohysterectomy)",def:"Surgical removal of the ovaries and uterus in female animals",breakdown:"Prevents unwanted litters, eliminates pyometra risk, reduces mammary cancer risk"},
  {term:"Neuter (castration)",def:"Surgical removal of the testicles in male animals",breakdown:"Reduces aggression, roaming, marking behavior, eliminates testicular cancer risk"},
  {term:"Microchip",def:"RFID chip (size of grain of rice) implanted under skin between shoulder blades for permanent ID",breakdown:"Cannot fall off like collar. Scanned at shelters/vets. Register with national database"},
  {term:"Vital signs — dog",def:"Normal: Temp 101-102.5°F, HR 60-140 bpm (size-dependent), RR 15-30 breaths/min",breakdown:"Smaller dogs have faster heart rates. Puppies have higher rates than adults"},
  {term:"Vital signs — cat",def:"Normal: Temp 100.5-102.5°F, HR 120-140 bpm, RR 20-30 breaths/min",breakdown:"Cats have naturally faster heart rates than dogs. Stress increases all values significantly"},
  {term:"Triage in veterinary medicine",def:"Prioritizing animal patients by severity: life-threatening (immediate) → serious → stable → minor",breakdown:"Same concept as human triage. Respiratory distress, severe bleeding, shock = immediate priority"},
  {term:"Parvovirus (canine)",def:"Highly contagious, life-threatening viral disease attacking the GI tract and immune cells in dogs",breakdown:"Symptoms: bloody diarrhea, vomiting, lethargy, dehydration. Preventable by vaccination. Spread by feces"},
  {term:"Heartworm disease",def:"Parasitic worms (Dirofilaria immitis) transmitted by mosquitoes that live in the heart and pulmonary arteries",breakdown:"Common in warm climates. Preventable with monthly medication. Treatment is expensive and risky"},
  {term:"Fleas and ticks",def:"External parasites causing anemia, skin disease, and transmitting diseases (Lyme, Rocky Mountain spotted fever)",breakdown:"Prevented with topical or oral monthly medications. Ticks must be removed within 24-36 hours to prevent disease"},
],
medium:[
  {term:"Anatomy — canine digestive system",def:"Mouth → Esophagus → Stomach → Small intestine (duodenum, jejunum, ileum) → Large intestine → Rectum → Anus",breakdown:"Dogs are omnivores. Stomach is single-chambered. Shorter intestinal tract than humans — faster digestion"},
  {term:"Anatomy — feline urinary system",def:"Kidneys → Ureters → Bladder → Urethra. Cats prone to urinary blockages, especially male cats",breakdown:"Male cat urethra is very narrow — prone to life-threatening urethral obstruction (FLUTD)"},
  {term:"Feline lower urinary tract disease (FLUTD)",def:"Umbrella term for conditions affecting the bladder and urethra in cats — crystals, blockage, infection",breakdown:"Signs: straining to urinate, blood in urine, crying out, vomiting, lethargy. Urethral blockage = emergency"},
  {term:"Canine bloat (GDV)",def:"Gastric Dilatation-Volvulus — stomach fills with gas and twists, cutting off blood supply",breakdown:"Affects large/giant breeds. Signs: distended abdomen, non-productive retching, restlessness. Life-threatening emergency"},
  {term:"Canine hip dysplasia",def:"Abnormal development of the hip joint causing pain and arthritis; genetic in large breeds",breakdown:"Common in German Shepherds, Labs, Golden Retrievers. Managed with medication, physical therapy, or surgery"},
  {term:"Diabetes mellitus in animals",def:"Cats: typically Type 2 (insulin resistance). Dogs: typically Type 1 (lack of insulin production)",breakdown:"Signs: polyuria, polydipsia, weight loss despite good appetite. Treated with insulin injections and diet"},
  {term:"Toxoplasma gondii",def:"Parasitic protozoan whose primary host is cats; zoonotic — can infect humans, especially dangerous in pregnancy",breakdown:"Cats shed oocysts in feces. Humans infected through cat litter, undercooked meat, gardening. Causes birth defects"},
  {term:"MRSA in veterinary medicine",def:"Methicillin-Resistant Staphylococcus aureus — antibiotic-resistant bacteria; zoonotic between pets and owners",breakdown:"Can pass between humans and pets. Treat infected wounds promptly. Handwashing after handling animals"},
  {term:"Euthanasia in veterinary medicine",def:"Humane ending of an animals life to relieve suffering — from Greek: eu (good) + thanatos (death)",breakdown:"Done with IV barbiturate overdose. Peaceful and painless. Ethical responsibility of veterinarians"},
  {term:"One Health concept",def:"Recognition that human health, animal health, and environmental health are interconnected and interdependent",breakdown:"~75% of emerging infectious diseases originate in animals. Veterinarians are critical to public health"},
  {term:"Antibiotic resistance in animals",def:"Overuse of antibiotics in livestock contributes to antibiotic-resistant bacteria affecting human medicine",breakdown:"WHO priority issue. MRSA, resistant Salmonella, resistant E. coli have zoonotic transmission to humans"},
  {term:"Wildlife veterinary medicine",def:"Care of wild animals in natural habitats, zoos, wildlife rehabilitation centers",breakdown:"Includes tracking, anesthesia for field procedures, disease surveillance, conservation medicine"},
  {term:"Canine body systems comparison to human",def:"Same major systems: cardiovascular, respiratory, digestive, nervous, musculoskeletal, endocrine, reproductive, integumentary",breakdown:"Key differences: 4-chambered heart (same), shorter digestive tract, more efficient temperature regulation via panting"},
  {term:"Veterinary pharmacology",def:"Many human medications also used in animals but at VERY different doses — never give human meds to pets without vet guidance",breakdown:"Acetaminophen (Tylenol): TOXIC to cats and dogs. Ibuprofen: TOXIC to both. Aspirin: risky in cats"},
  {term:"Animal behavior and stress",def:"Fear, anxiety, and stress significantly affect animal health and ability to be examined/treated",breakdown:"Low-stress handling: Fear Free techniques, towel wraps for cats, approaching from side not front for dogs"},
],
hard:[
  {term:"Pharmacokinetics in animals vs humans",def:"Drug metabolism differs significantly between species — what is safe for one may be toxic to another",breakdown:"Cats lack glucuronyl transferase → cannot metabolize many drugs. Dogs more similar to humans but still different"},
  {term:"Feline acetaminophen toxicity mechanism",def:"Cats cannot glucuronidate acetaminophen → toxic metabolites accumulate → oxidative damage to RBCs (methemoglobin) and liver",breakdown:"Signs: brown gums (methemoglobinemia), facial swelling, respiratory distress. Antidote: N-acetylcysteine. Fatal without treatment"},
  {term:"Anesthesia monitoring in animals",def:"Monitor: heart rate, respiratory rate, blood pressure, SpO2, end-tidal CO2, temperature, depth of anesthesia",breakdown:"Animals cannot report pain — monitoring is critical. Brachycephalic breeds (pugs, bulldogs) higher anesthesia risk"},
  {term:"Antimicrobial stewardship in veterinary medicine",def:"Judicious use of antibiotics to reduce development of antimicrobial resistance",breakdown:"Culture and sensitivity testing before prescribing. Avoid prophylactic use. Critical to One Health approach"},
  {term:"Veterinary public health role",def:"Vets inspect food supply, monitor zoonotic diseases, control animal-source outbreaks, develop vaccines",breakdown:"USDA veterinarians inspect 9 billion animals annually. CDC employs veterinarians in epidemiology"},
]},
quiz:{
easy:[
  {q:"The term 'feline' refers to which animal?",opts:["Dogs","Horses","Cats","Rabbits"],correct:2,explain:"Feline comes from Latin 'felis' meaning cat. Feline medicine is the specialty focused on cat health. Other species terms: canine (dogs), equine (horses), bovine (cattle)."},
  {q:"Which disease can be transmitted from animals to humans (zoonosis)?",opts:["Canine hip dysplasia","Heartworm disease","Rabies","Feline hyperthyroidism"],correct:2,explain:"Rabies is a classic zoonotic disease — transmitted from infected animals to humans through bites containing infected saliva. It is almost always fatal once symptoms appear. Vaccination of pets prevents transmission."},
  {q:"Core vaccines for dogs include:",opts:["Rabies and DHPP","Only Bordetella","Lyme disease vaccine only","No vaccines are needed for indoor dogs"],correct:0,explain:"Core dog vaccines: Rabies (legally required in most states) and DHPP (Distemper, Hepatitis, Parvovirus, Parainfluenza). These protect against the most serious, common, or contagious diseases. Given at 8, 12, 16 weeks then annually/every 3 years."},
  {q:"Spaying a female dog involves:",opts:["Removing the uterus only","Removing ovaries and uterus (ovariohysterectomy)","Removing the mammary glands","Hormone injections"],correct:1,explain:"Spay = ovariohysterectomy (removal of ovaries and uterus). Benefits: prevents unwanted litters, eliminates pyometra (uterine infection) risk, reduces mammary cancer risk if done before first heat."},
  {q:"Normal heart rate for a healthy adult cat is:",opts:["60-80 bpm","80-100 bpm","120-140 bpm","150-180 bpm"],correct:2,explain:"Normal cat heart rate is 120-140 bpm — much faster than humans (60-100 bpm) because cats are smaller animals with higher metabolic rates. Stress can increase this significantly during vet visits."},
  {q:"Parvovirus in dogs primarily attacks the:",opts:["Respiratory system","Gastrointestinal tract and immune cells","Nervous system","Urinary tract"],correct:1,explain:"Canine parvovirus attacks rapidly dividing cells — intestinal lining cells and immune cells (bone marrow). Causes bloody diarrhea, vomiting, severe dehydration. Highly contagious, spread through feces. Preventable with vaccination."},
  {q:"The DVM degree means:",opts:["Domestic Veterinary Medicine","Doctor of Veterinary Medicine","Department of Veterinary Medicine","Diagnostic Veterinary Method"],correct:1,explain:"DVM = Doctor of Veterinary Medicine. This is the professional degree required to practice veterinary medicine in the US. Requires 4 years of veterinary school after a bachelors degree — similar in length to an MD."},
  {q:"Which common human medication is TOXIC to cats?",opts:["Penicillin","Acetaminophen (Tylenol)","Vitamin C","Saline solution"],correct:1,explain:"Acetaminophen (Tylenol) is TOXIC to cats — they lack the liver enzyme (glucuronyl transferase) needed to safely metabolize it. Even one regular-strength Tylenol can be fatal to a cat. Never give human medications to pets without vet guidance."},
],
medium:[
  {q:"The 'One Health' concept refers to:",opts:["All humans having equal access to healthcare","The connection between human health, animal health, and environmental health","One global health organization","A single disease affecting all species"],correct:1,explain:"One Health recognizes that human health, animal health, and ecosystem health are deeply interconnected. About 75% of emerging infectious diseases originate in animals. Veterinarians play a critical public health role in disease surveillance and outbreak control."},
  {q:"Canine GDV (bloat) is life-threatening because:",opts:["It causes severe pain only","The stomach fills with gas and twists, cutting off blood supply to the stomach and spleen","It prevents the dog from eating","It causes respiratory distress only"],correct:1,explain:"GDV (Gastric Dilatation-Volvulus) = the stomach dilates with gas AND twists (volvulus), cutting off blood supply to itself, the spleen, and nearby organs. Without emergency surgery within hours, it is fatal. Most common in large, deep-chested breeds."},
  {q:"Why is acetaminophen toxic specifically to cats?",opts:["Cats absorb it too quickly","Cats lack an enzyme to metabolize it safely, causing toxic buildup that damages red blood cells and liver","Cats are simply more sensitive to pain medications","Acetaminophen causes allergic reactions in all animals"],correct:1,explain:"Cats lack sufficient glucuronyl transferase — the liver enzyme that breaks down acetaminophen safely. The toxic metabolite accumulates, causing methemoglobinemia (brown gums, oxygen cannot be carried) and severe liver damage. Fatal without immediate treatment."},
  {q:"FLUTD (Feline Lower Urinary Tract Disease) is most dangerous in:",opts:["Female cats of all ages","Male kittens only","Male cats due to their narrow urethra that can become completely blocked","Elderly cats of both sexes equally"],correct:2,explain:"Male cats have a much narrower urethra than female cats. When crystals or mucus accumulate, the urethra can become completely blocked — preventing urination. A blocked cat cannot eliminate toxins and will die within 24-72 hours without emergency treatment."},
]
}
}; // end QB_VETERINARY

// ── PUBLIC HEALTH ────────────────────────────────────────────────────────
window.QB_PUBLIC_HEALTH = {
flashcards:{
easy:[
  {term:"Public health definition",def:"The science and art of preventing disease, prolonging life, and promoting health through organized community efforts",breakdown:"Focus on POPULATIONS, not individuals. Prevention rather than treatment. Government + community action"},
  {term:"2025-2026 HOSA Public Health topic",def:"Food Wars: Battling Big Soda and Ultra-Processed Food — examining industry influence on diet and health policy",breakdown:"Examines how food marketing, lobbying, and corporate influence affect public nutrition and chronic disease rates"},
  {term:"Ultra-processed foods (UPF)",def:"Foods manufactured with ingredients and processes not used in home cooking: additives, emulsifiers, artificial flavors, colors",breakdown:"NOVA classification Group 4. Examples: chips, soda, fast food, packaged snacks, frozen meals, breakfast cereals"},
  {term:"NOVA food classification system",def:"4-group food classification based on degree of processing: 1=unprocessed, 2=processed culinary ingredients, 3=processed, 4=ultra-processed",breakdown:"Developed by Brazilian epidemiologist Carlos Monteiro. More useful than nutrients alone for predicting diet quality"},
  {term:"Sugar-sweetened beverages (SSBs)",def:"Drinks with added sugars: sodas, sports drinks, energy drinks, sweetened juices, flavored milk, sweetened teas",breakdown:"Leading source of added sugar in American diet. Linked to obesity, T2DM, heart disease, dental caries"},
  {term:"Added sugars",def:"Sugars added to foods during processing — NOT naturally occurring sugars in whole fruits and vegetables",breakdown:"Dietary Guidelines: <10% of daily calories from added sugars. Average American consumes 17 teaspoons daily — nearly double the limit"},
  {term:"High-fructose corn syrup (HFCS)",def:"Sweetener made from corn starch; major ingredient in sodas and processed foods; metabolized differently than glucose",breakdown:"Metabolized primarily in liver → fat storage → linked to NAFLD, insulin resistance. Used because it is cheaper than cane sugar"},
  {term:"Food desert",def:"Geographic area where affordable, nutritious food is difficult to access — typically low-income communities",breakdown:"~23 million Americans live in food deserts. Linked to higher rates of obesity, diabetes, cardiovascular disease"},
  {term:"Food swamp",def:"Area with high density of fast food and convenience stores relative to healthy food options",breakdown:"Research shows food swamps more strongly predict obesity than food deserts. Concentration of unhealthy options is the key factor"},
  {term:"Food marketing to children",def:"Advertising targeting children for high-sugar, high-fat, low-nutrient products through TV, social media, packaging, schools",breakdown:"Children see 4,000-7,000 food ads/year. 80% are for nutrient-poor foods. Linked to preference formation and brand loyalty"},
  {term:"Soda tax (sugar-sweetened beverage tax)",def:"Government tax on sugary drinks to reduce consumption and generate revenue for public health programs",breakdown:"Philadelphia: 1.5 cents/oz. Berkeley CA: first US city SSB tax. Evidence shows 20-30% reduction in consumption"},
  {term:"Obesity epidemic statistics",def:"42% of US adults obese (BMI≥30). 19% of children ages 2-19. Leading preventable cause of death behind smoking",breakdown:"Costs US healthcare system $173 billion annually. Strongly correlated with ultra-processed food consumption"},
  {term:"Type 2 diabetes and diet",def:"Strong link between SSB consumption, ultra-processed food diet, and Type 2 diabetes development",breakdown:"Each additional SSB per day = 26% increased T2DM risk. Weight loss of 5-7% can prevent or reverse T2DM"},
  {term:"Food industry lobbying",def:"Spending by food/beverage companies to influence government nutrition policy, dietary guidelines, and regulations",breakdown:"Coca-Cola, PepsiCo, and processed food companies spend $30M+/year lobbying against nutrition regulations"},
  {term:"Epidemiology",def:"The study of how often diseases occur in different groups of people and why — the foundation of public health",breakdown:"Epidemiologists track disease outbreaks, identify risk factors, and evaluate interventions. 'Disease detectives'"},
  {term:"Social determinants and diet",def:"Income, education, neighborhood, culture, and food environment all shape what people eat",breakdown:"Cannot address poor diet with nutrition education alone — must address structural/environmental factors"},
  {term:"Chronic disease burden",def:"Heart disease, cancer, diabetes, obesity — leading causes of death AND disability; largely preventable through diet and lifestyle",breakdown:"Chronic diseases account for 90% of $4.1 trillion US healthcare spending annually"},
  {term:"Health promotion",def:"Enabling people to increase control over their health through education, policy, community action, and environment",breakdown:"Ottawa Charter (1986): education, social/economic policy, community participation, environment, health services"},
  {term:"Disease prevention levels",def:"Primary (prevent disease), Secondary (early detection), Tertiary (manage existing disease)",breakdown:"Public health focuses most on primary prevention — vaccines, clean water, nutrition policy, anti-tobacco laws"},
  {term:"CDC (Centers for Disease Control and Prevention)",def:"US federal agency responsible for tracking disease, conducting research, and developing health promotion/prevention programs",breakdown:"Founded 1946. Atlanta-based. Employs veterinarians, epidemiologists, nurses, physicians, data scientists"},
],
medium:[
  {term:"Food industry tactics (Big Tobacco parallel)",def:"Industry funds biased research, disputes scientific consensus, lobbies against regulations, targets children — same playbook as tobacco",breakdown:"Coca-Cola funded research minimizing sugars role in obesity. Similar to tobacco industry funding on smoking"},
  {term:"Front-of-package nutrition labeling",def:"Simplified nutrition information on the FRONT of food packages to help consumers make quick decisions",breakdown:"Chiles 'stop sign' black warning labels → 25% reduction in purchase of labeled products. US FDA developing similar rules"},
  {term:"School food environment",def:"Foods and beverages available in schools (cafeteria, vending, a la carte) significantly influence childrens diet quality",breakdown:"USDA Healthy, Hunger-Free Kids Act (2010) improved school meal standards. Industry lobbied against pizza/tomato paste rules"},
  {term:"Portion size distortion",def:"Dramatic increase in standard serving sizes over decades — Americans now expect and consume much larger portions",breakdown:"McDonalds original 1955 soda: 7 oz. Todays large: 30 oz. Movie popcorn grew from 1 cup to 20+ cups"},
  {term:"Advertising to low-income communities",def:"Research shows targeted marketing of unhealthy foods in minority and low-income communities — health equity issue",breakdown:"Fast food advertising disproportionately targets Black and Hispanic children via specific TV channels and neighborhood density"},
  {term:"Gut microbiome and UPF",def:"Ultra-processed food additives (emulsifiers, artificial sweeteners) alter gut bacteria composition, contributing to inflammation",breakdown:"Carrageenan, polysorbate-80, and saccharin found to disrupt gut microbiome in research studies"},
  {term:"Brazils public health model",def:"Brazils 2014 Dietary Guidelines became world model — first to recommend avoiding ultra-processed foods as a category",breakdown:"Recommends: 'Eat mostly unprocessed or minimally processed foods.' Translated to 60+ countries' guidelines"},
  {term:"Sugar addiction neuroscience",def:"Sugar activates same reward (dopamine) pathways as addictive drugs. Ultra-processed foods engineered to maximize palatability",breakdown:"Industry concept: 'bliss point' — perfect combination of sugar, fat, salt that makes food irresistible and promotes overconsumption"},
  {term:"Policy interventions for diet",def:"SSB taxes, menu labeling, food marketing restrictions, school food standards, zoning for food access, WIC/SNAP reforms",breakdown:"Multi-level intervention needed: individual + community + policy + environment. No single solution works alone"},
  {term:"Nutrient profiling",def:"Scientific systems rating foods by their overall nutritional quality — used to restrict marketing of unhealthy foods to children",breakdown:"WHO developed global nutrient profile model. Used in UK, Chile, Mexico to regulate advertising. US lags behind"},
  {term:"Food sovereignty vs food security",def:"Food security: people have access to enough safe, nutritious food. Food sovereignty: communities control their own food systems",breakdown:"Indigenous and community food sovereignty movements challenge industrial food system dominance"},
  {term:"Public health research methods",def:"Cohort studies, case-control studies, randomized controlled trials, systematic reviews, population surveillance",breakdown:"Epidemiological evidence shows association — experimental evidence shows causation. Both needed for policy"},
],
hard:[
  {term:"NOVA Group 4 health effects evidence",def:"Systematic reviews show UPF consumption linked to: obesity (+26%), T2DM (+15%), CVD (+12%), depression, cancer, all-cause mortality",breakdown:"Over 40 prospective cohort studies consistently show dose-response relationship. Causality debated but evidence growing"},
  {term:"Industry-funded research bias",def:"Studies funded by food industry are 4-8x more likely to show favorable results than independently funded studies",breakdown:"Systematic review of 206 SSB studies: industry-funded = 5x less likely to show SSB-health harm link. Same pattern as tobacco"},
  {term:"Regulatory capture",def:"When regulatory agencies (FDA, USDA) become dominated by the industry they regulate, protecting industry over public",breakdown:"Revolving door between food industry and FDA/USDA is well-documented. Limits effectiveness of food safety regulations"},
  {term:"FAFH (Food Away From Home)",def:"Food consumed outside the home now accounts for >50% of American food spending and calories",breakdown:"Restaurant/fast food portions larger, higher in calories, saturated fat, sodium than home-cooked meals"},
  {term:"Food systems approach",def:"Examining the entire food system from farm to consumer — production, processing, distribution, marketing, consumption, waste",breakdown:"Upstream factors (farming, processing, retail) have greater impact on population diet than individual choices alone"},
]},
quiz:{
easy:[
  {q:"The 2025-2026 HOSA Public Health topic focuses on:",opts:["Climate change and health","Food Wars: Battling Big Soda and Ultra-Processed Food","Mental health in adolescents","Antibiotic resistance"],correct:1,explain:"The HOSA Public Health event for 2025-2026 focuses on 'Food Wars: Battling Big Soda and Ultra-Processed Food' — examining how the food and beverage industry influences diet quality, public health policy, and chronic disease rates."},
  {q:"Ultra-processed foods (UPF) are best defined as:",opts:["Any food with more than 5 ingredients","Foods manufactured using industrial processes and ingredients not found in home cooking","Foods that are high in fat only","Any fast food item"],correct:1,explain:"Ultra-processed foods (NOVA Group 4) are manufactured with industrial processes and ingredients — additives, emulsifiers, artificial flavors/colors — not used in home cooking. Examples: sodas, chips, packaged snacks, most breakfast cereals, fast food."},
  {q:"A sugar-sweetened beverage (SSB) tax is a public health intervention designed to:",opts:["Punish soda companies","Generate tax revenue only","Reduce consumption of sugary drinks and fund health programs","Ban soda from schools"],correct:2,explain:"SSB taxes make sugary drinks more expensive, which research shows reduces consumption by 20-30%. Revenue often funds nutrition programs, obesity prevention, and healthcare. Berkeley CA was first US city; Philadelphias tax raised $78M for education programs."},
  {q:"What is a 'food desert'?",opts:["A hot, dry area where food does not grow","Geographic area with limited access to affordable, nutritious food","A diet plan eliminating desserts","A restaurant with no vegetables on the menu"],correct:1,explain:"A food desert is a geographic area — typically low-income — where residents lack easy access to affordable, fresh, nutritious food. About 23 million Americans live in food deserts. Linked to higher rates of obesity, diabetes, and cardiovascular disease."},
  {q:"The CDC (Centers for Disease Control) primarily focuses on:",opts:["Treating individual patients","Funding hospitals","Tracking diseases, conducting research, and developing prevention programs for populations","Drug approval"],correct:2,explain:"The CDC is a federal public health agency focused on population health — disease surveillance, outbreak investigation, research, and health promotion/prevention programs. It employs epidemiologists, veterinarians, nurses, physicians, and data scientists."},
  {q:"Public health differs from clinical medicine primarily by:",opts:["Using different medications","Focusing on disease prevention in populations rather than treating individual patients","Only working with infectious diseases","Having no role in chronic disease"],correct:1,explain:"Clinical medicine focuses on diagnosing and treating individual patients. Public health focuses on preventing disease and promoting health in entire communities and populations. Public health includes policy, education, epidemiology, and environmental interventions."},
  {q:"Added sugars in the American diet — the Dietary Guidelines recommend limiting them to:",opts:["<25% of daily calories","<10% of daily calories","<20% of daily calories","There is no recommended limit"],correct:1,explain:"Dietary Guidelines for Americans recommend <10% of daily calories from added sugars. For a 2,000-calorie diet, that is <200 calories or ~50g (~12 teaspoons). Average American consumes ~17 teaspoons daily — far exceeding this limit."},
  {q:"The NOVA food classification system categorizes foods based on:",opts:["Calorie content","Fat percentage","Degree of industrial processing","Country of origin"],correct:2,explain:"NOVA classifies foods into 4 groups based on processing degree: 1=unprocessed/minimally processed (whole foods), 2=culinary ingredients (oil, salt), 3=processed foods, 4=ultra-processed foods. More predictive of health outcomes than traditional nutrient-based classifications."},
],
medium:[
  {q:"High-fructose corn syrup (HFCS) is linked to unique health concerns because:",opts:["It contains more calories than regular sugar","It is metabolized primarily in the liver, promoting fat storage and insulin resistance","It is found in diet sodas only","It causes immediate allergic reactions"],correct:1,explain:"HFCS is metabolized primarily in the liver (unlike glucose which is used by all cells). Liver converts excess fructose to fat → NAFLD (non-alcoholic fatty liver disease), insulin resistance, elevated triglycerides. The liver cannot regulate fructose uptake like glucose."},
  {q:"The 'Big Tobacco parallel' in food industry refers to:",opts:["Both industries sell similar products","Food companies use the same tactics as tobacco — funding biased research, lobbying, targeting children, disputing science","Food is as addictive as cigarettes","Tobacco companies now own food companies"],correct:1,explain:"Public health researchers have documented that the food industry (especially Big Soda) uses the same playbook as tobacco: funding studies showing favorable results, disputing independent science, lobbying against regulations, and targeting children with marketing."},
  {q:"Chiles 'stop sign' warning labels on ultra-processed foods led to:",opts:["No change in behavior","Increased consumption of labeled products","About 25% reduction in purchase of labeled products","Complete elimination of junk food from Chile"],correct:2,explain:"Chile implemented mandatory black octagonal 'STOP' labels on foods high in sugar, fat, sodium, or calories in 2016. Studies showed ~25% reduction in purchase of labeled products and shift toward healthier alternatives — now a global model for front-of-package labeling."},
  {q:"A 'food swamp' differs from a 'food desert' because:",opts:["Food swamps have NO food access at all","Food swamps are rural areas only","Food swamps have abundant unhealthy food options overwhelming healthier choices — more predictive of obesity","There is no difference"],correct:2,explain:"Food deserts = insufficient healthy food access. Food swamps = overwhelmingly more fast food/convenience stores than healthy options. Research finds food swamps more strongly predict obesity rates than food deserts — it is not just about lack of access, but the ratio of unhealthy to healthy options."},
  {q:"The goal of the HOSA Public Health event is for teams to:",opts:["Memorize nutrition facts","Research the topic and present evidence-based solutions to a panel of judges","Create a diet plan","Interview community members only"],correct:1,explain:"HOSA Public Health is a team event (2-6 members) requiring research of the designated topic, development of evidence-based community health interventions, and presentation to a judge panel. Teams must demonstrate understanding of epidemiology, health disparities, and intervention strategies."},
]
}
}; // end QB_PUBLIC_HEALTH

