// STOP THE BLEED - expand to 45 easy cards total
window.QB_STOP_BLEED.flashcards.easy = window.QB_STOP_BLEED.flashcards.easy.concat([
  {term:"Arterial bleeding",def:"Bright red blood spurting with each heartbeat — highest priority bleeding",breakdown:"Arteries carry oxygenated blood under high cardiac pressure. Spurting indicates arterial source"},
  {term:"Venous bleeding",def:"Dark red blood flowing steadily — less immediately dangerous than arterial",breakdown:"Veins carry deoxygenated blood at lower pressure. Still can be life-threatening if large vein"},
  {term:"Capillary bleeding",def:"Slow oozing from small surface wounds — lowest priority bleeding type",breakdown:"Tiny blood vessels. Usually stops with direct pressure within minutes. Band-aids handle these"},
  {term:"Exsanguination",def:"Death from blood loss — can occur in 3-5 minutes from major arterial wound",breakdown:"Exsanguinate = drain of blood. Reason why Stop the Bleed training targets bystanders"},
  {term:"Hemostasis",def:"The process of stopping bleeding through clot formation",breakdown:"Hemo = blood, stasis = stopping. Three stages: vascular spasm → platelet plug → coagulation"},
  {term:"Clot formation",def:"Blood thickening at wound site through platelet aggregation and fibrin mesh",breakdown:"Takes 3-5 minutes for initial clot. Pressure helps by slowing flow and concentrating platelets"},
  {term:"Proximal",def:"Closer to the center of the body — tourniquet goes PROXIMAL to wound",breakdown:"Latin: proximus = nearest. Opposite of distal. Proximal thigh = upper thigh near hip"},
  {term:"Distal",def:"Further from the center of the body — wound is distal to tourniquet",breakdown:"Latin: distare = to be distant. Distal finger = fingertip. Check distal pulse after tourniquet"},
  {term:"Ischemia",def:"Tissue damage from lack of blood flow — risk when tourniquet is applied too long",breakdown:"Greek: isch = to hold back. Tourniquet ischemia: irreversible damage after 6+ hours typically"},
  {term:"Tourniquet time limit",def:"Tourniquets safe for up to 2 hours generally; 6 hours maximum in extreme cases",breakdown:"Military data: limb loss risk increases significantly after 2 hours. Always document time"},
  {term:"CAT tourniquet",def:"Combat Application Tourniquet — standard military/civilian bleed control device",breakdown:"One-handed application. Self-tightening windlass mechanism. 1.5 inch wide band"},
  {term:"SOFT-T Wide",def:"Special Operations Forces Tourniquet Wide — another common military tourniquet",breakdown:"2-inch wide for better pressure distribution. Used by Special Forces. Also civilian option"},
  {term:"Windlass",def:"The rod or stick twisted to tighten an improvised or CAT tourniquet",breakdown:"Windlass mechanics: twisting rod creates mechanical advantage to tighten band around limb"},
  {term:"Pressure dressing",def:"Snug bandage maintaining direct pressure after initial bleeding control",breakdown:"Apply after packing or direct pressure controls bleeding. Prevents dressing shifting during transport"},
  {term:"Shock",def:"Life-threatening circulatory failure — not enough blood reaching vital organs",breakdown:"Hemorrhagic shock: classes I-IV based on blood loss. Class III-IV require immediate intervention"},
  {term:"Signs of shock",def:"Pale cool clammy skin, rapid weak pulse, confusion, rapid breathing, low BP",breakdown:"CUPS: Cold/clammy skin, Unresponsive or confused, Pale skin, Sweating. Lay flat, keep warm"},
  {term:"Recovery position (post-bleed)",def:"Lying flat, legs elevated 6-12 inches if no spinal injury, kept warm",breakdown:"Elevating legs shifts blood to vital organs. Warmth prevents hypothermia worsening coagulopathy"},
  {term:"Scene safety survey",def:"Rapid assessment before approaching victim: is scene safe? what happened? how many victims?",breakdown:"Do not become a second victim. Assess: traffic, active threat, unstable structure, electrical"},
  {term:"Good Samaritan law",def:"Legal protection for bystanders who provide emergency care in good faith",breakdown:"All 50 states have Good Samaritan laws. Fear of legal liability should never delay care"},
  {term:"EMS handoff report",def:"Telling paramedics: time of tourniquet, what was done, patient status trend",breakdown:"Critical info: TK time (tissue viability), interventions (packing, pressure), mental status trend"},
]);

// VETERINARY - expand to 60 easy cards
window.QB_VETERINARY.flashcards.easy = window.QB_VETERINARY.flashcards.easy.concat([
  {term:"Anatomy",def:"Study of the structure of the body — same organ systems as humans in most mammals",breakdown:"Greek: anatome = cutting up. Comparative anatomy: vertebrates share heart, lungs, kidneys, brain"},
  {term:"Physiology",def:"Study of how body systems function — how organs do their jobs",breakdown:"Greek: physis = nature. Pathophysiology = how disease disrupts normal function"},
  {term:"Veterinarian",def:"Doctor of Veterinary Medicine (DVM) — licensed to diagnose and treat animal diseases",breakdown:"Requires 4-year vet school after bachelor's degree. Similar length and rigor to medical school"},
  {term:"Veterinary technician (RVT)",def:"Licensed vet tech — performs procedures, administers drugs, assists in surgery under DVM supervision",breakdown:"2-4 year degree. The nurses of veterinary medicine. Cannot diagnose or prescribe independently"},
  {term:"Veterinary assistant",def:"Entry-level vet team member — restrains animals, cleans, basic patient care, no licensure required",breakdown:"On-the-job training or certificate programs. Often first step into veterinary career"},
  {term:"Companion animal",def:"Animal kept primarily for companionship rather than work or food — dogs, cats, rabbits, birds",breakdown:"Also called pets. 67% of US households own pets. Companion animal vet practice = small animal"},
  {term:"Livestock",def:"Animals raised for food, fiber, or work: cattle, pigs, chickens, sheep, goats, horses",breakdown:"Also called food animals or production animals. Food animal vet = large animal practice"},
  {term:"Exotic animal",def:"Non-traditional pets: reptiles (snakes, lizards, turtles), small mammals (rabbits, ferrets, guinea pigs)",breakdown:"Requires specialized knowledge. Reptiles are ectothermic (cold-blooded) — very different physiology"},
  {term:"Restraint",def:"Safely controlling an animal for examination or treatment without causing injury to animal or handler",breakdown:"Physical, chemical (sedation), or mechanical (muzzle, cone). Fear-free techniques reduce stress"},
  {term:"Muzzle",def:"Device placed over animal's mouth to prevent biting during examination or treatment",breakdown:"Used in anxious or painful dogs. NEVER use on cats (they vomit and could aspirate). Basket vs soft"},
  {term:"Microchip (RFID)",def:"Radio-frequency chip (rice grain size) implanted under skin for permanent identification",breakdown:"15-digit ISO number. Scanned at shelters and vet offices. Cannot fall off like a collar tag"},
  {term:"Stethoscope",def:"Instrument for listening to heart and lung sounds (auscultation)",breakdown:"Two-headed: bell for low sounds (murmurs), diaphragm for high sounds (breath sounds, bowel)"},
  {term:"Otoscope",def:"Instrument for examining the ear canal and eardrum",breakdown:"Oto = ear, scope = to look. Detects ear infections, foreign bodies, parasites (ear mites)"},
  {term:"Ophthalmoscope",def:"Instrument for examining the interior of the eye — retina, optic nerve",breakdown:"Ophthalmo = eye. Detects cataracts, retinal detachment, glaucoma signs"},
  {term:"Thermometer",def:"Measures body temperature — rectal in most animals for accuracy",breakdown:"Normal: dogs 101-102.5°F, cats 100.5-102.5°F. Fever = 103°F+. Hypothermia = below 99°F"},
  {term:"Pulse",def:"Rhythmic pressure wave in arteries from heart contractions — assessed at femoral artery in dogs/cats",breakdown:"Normal dog: 60-140 bpm. Normal cat: 120-140 bpm. Puppies and kittens have faster rates"},
  {term:"Respiratory rate",def:"Number of breaths per minute — watch chest rise or feel air movement",breakdown:"Normal dog: 15-30/min. Normal cat: 20-30/min. Panting is normal in dogs for thermoregulation"},
  {term:"Mucous membrane color",def:"Gum color assesses circulation — normal is salmon pink, moist",breakdown:"Pale: anemia or shock. White: severe shock. Blue (cyanotic): oxygen deprivation. Yellow: jaundice"},
  {term:"Capillary refill time (CRT)",def:"Gum blanched with finger pressure should return to pink within 1-2 seconds",breakdown:"Tests peripheral circulation. >2 seconds = poor perfusion (shock, dehydration). Check gums"},
  {term:"Dehydration assessment",def:"Skin tent test: pinch skin at scruff — returns to normal immediately if hydrated",breakdown:"Mild: 5-7%. Moderate: 8-10%. Severe: >10% (eyes sunken, gums tacky). Treat with IV or SQ fluids"},
  {term:"Neuter",def:"Surgical removal of testicles in male animals — also called castration or orchiectomy",breakdown:"Benefits: reduces aggression, roaming, marking, testicular cancer risk, prostate disease"},
  {term:"Spay",def:"Surgical removal of ovaries and uterus (ovariohysterectomy) in female animals",breakdown:"Benefits: eliminates heat cycles, prevents pyometra, reduces mammary tumor risk if done early"},
  {term:"Pyometra",def:"Life-threatening infection of the uterus in unspayed female dogs and cats",breakdown:"Pyometra = pus in uterus. Closed: no discharge — most dangerous. Treatment: emergency spay"},
  {term:"Heartworm prevention",def:"Monthly oral or topical medication containing ivermectin or milbemycin kills heartworm larvae",breakdown:"Prevention is easy and cheap. Treatment of adult heartworms is difficult, expensive, and risky"},
  {term:"Flea life cycle",def:"Egg → larva → pupa → adult — 4 stages, takes 2-8 weeks depending on temperature",breakdown:"95% of flea population is in environment (eggs, larvae, pupae) not on pet. Treat pet AND home"},
  {term:"Tick removal",def:"Grasp tick at skin surface with fine tweezers, pull straight out with steady pressure",breakdown:"Do not twist, burn, or smother. Clean with alcohol. Save tick in sealed bag for identification"},
  {term:"Annual wellness exam",def:"Yearly physical examination + vaccines + parasite screening + blood/urine tests",breakdown:"Preventive care catches disease early. Pets age faster than humans — annual = every 5-7 human years"},
  {term:"AVMA",def:"American Veterinary Medical Association — professional organization governing US veterinary medicine",breakdown:"Sets standards, accredits vet schools, publishes guidelines. Similar to AMA for human medicine"},
  {term:"Kennel cough (Bordetella)",def:"Highly contagious upper respiratory infection in dogs — dry honking cough",breakdown:"Bordetella bronchiseptica + viruses. Spread in kennels, dog parks, groomers. Vaccine available"},
  {term:"Leptospirosis",def:"Bacterial disease spread through urine of infected animals and contaminated water — zoonotic",breakdown:"Affects kidneys and liver. Risk: standing water, wildlife contact. Vaccine available for dogs"},
]);

// PUBLIC HEALTH - expand to 50 easy cards
window.QB_PUBLIC_HEALTH.flashcards.easy = window.QB_PUBLIC_HEALTH.flashcards.easy.concat([
  {term:"Health promotion",def:"Enabling people to increase control over and improve their health",breakdown:"Ottawa Charter 1986: healthy public policy, supportive environments, community action, skills, health services"},
  {term:"Primary prevention",def:"Preventing disease BEFORE it occurs — vaccines, nutrition education, seatbelts",breakdown:"Remove the cause. Examples: fluoride in water, HPV vaccine, no-smoking policies, prenatal care"},
  {term:"Secondary prevention",def:"Early detection to stop disease from progressing — screening, early diagnosis",breakdown:"Find disease early. Examples: mammograms, colonoscopies, blood pressure checks, HIV testing"},
  {term:"Tertiary prevention",def:"Managing existing disease to prevent complications and disability",breakdown:"Reduce impact. Examples: cardiac rehab, diabetes management programs, dialysis, physical therapy"},
  {term:"Health disparities",def:"Preventable differences in health outcomes between population groups — linked to social factors",breakdown:"Race, income, education, geography shape health. LGBTQ+, racial minorities, low-income bear greater burden"},
  {term:"Social determinants of health",def:"Non-medical factors shaping health outcomes: income, education, housing, neighborhood, food access",breakdown:"Account for 80% of health outcomes. Clinical care only responsible for ~20%. Must address root causes"},
  {term:"BMI (Body Mass Index)",def:"Weight(kg) / Height(m)^2 — screening tool for weight categories, NOT a measure of health",breakdown:"Limitations: does not distinguish muscle from fat. Underestimates disease risk in some ethnicities"},
  {term:"Obesity",def:"BMI ≥ 30 — associated with T2DM, heart disease, cancer, sleep apnea, joint disease",breakdown:"42% of US adults obese. Complex causes: genetics, environment, psychology, food system, activity"},
  {term:"Chronic disease",def:"Long-lasting condition (3+ months) not self-resolving: heart disease, diabetes, cancer, COPD",breakdown:"Top causes of US death and disability. Largely preventable through diet, exercise, no smoking"},
  {term:"Communicable disease",def:"Illness spread from person to person or from animals/environment to people",breakdown:"AKA infectious disease. Spread by direct contact, droplets, airborne, fecal-oral, vectors"},
  {term:"Non-communicable disease",def:"Disease NOT transmitted person-to-person — heart disease, cancer, diabetes, mental illness",breakdown:"Leading cause of global death. Risk factors: tobacco, unhealthy diet, physical inactivity, alcohol"},
  {term:"Vector",def:"Organism that transmits disease between hosts — mosquitoes, ticks, fleas, sandflies",breakdown:"Vector-borne diseases: malaria, dengue, Lyme, West Nile, Zika, plague. Warming climate expanding ranges"},
  {term:"Herd immunity",def:"Indirect protection when enough of a population is immune — prevents spread to vulnerable people",breakdown:"Threshold varies: measles needs 95% immunity. Polio 80-85%. Flu ~75% (changes annually)"},
  {term:"Quarantine vs isolation",def:"Quarantine: separates exposed people. Isolation: separates infected people",breakdown:"Quarantine = may have been exposed, precautionary. Isolation = confirmed infected, must separate"},
  {term:"Contact tracing",def:"Identifying and notifying people who may have been exposed to an infectious disease",breakdown:"Core outbreak control tool. COVID-19 made this widely known. Also used for TB, STIs, foodborne"},
  {term:"Foodborne illness",def:"Disease caused by eating contaminated food — bacteria, viruses, parasites, toxins",breakdown:"48 million Americans get food poisoning annually. 128,000 hospitalizations, 3,000 deaths per year"},
  {term:"Salmonella",def:"Bacteria in raw poultry, eggs, reptiles — causes diarrhea, fever, cramps 12-72 hours after exposure",breakdown:"Most common cause of food poisoning deaths. Cook poultry to 165°F. Wash hands after handling"},
  {term:"E. coli O157:H7",def:"Dangerous bacteria in undercooked beef, raw produce, contaminated water",breakdown:"Produces Shiga toxin. Can cause hemolytic uremic syndrome (HUS) — kidney failure in children"},
  {term:"Food safety HACCP",def:"Hazard Analysis Critical Control Points — systematic approach to preventing food safety hazards",breakdown:"7 principles: hazard analysis → CCPs → critical limits → monitoring → corrective action → verification → records"},
  {term:"Caloric balance",def:"Calories in (food) vs calories out (BMR + activity) — determines weight",breakdown:"3,500 calorie deficit = roughly 1 pound lost. BUT: oversimplified — quality matters as much as quantity"},
  {term:"Macronutrients",def:"Carbohydrates, proteins, fats — provide energy (calories) to the body",breakdown:"Carbs: 4 cal/g. Protein: 4 cal/g. Fat: 9 cal/g. Water is a nutrient but provides no calories"},
  {term:"Micronutrients",def:"Vitamins and minerals — needed in small amounts for body functions, no calories",breakdown:"Fat-soluble (A,D,E,K) stored in fat. Water-soluble (C, B vitamins) excreted daily — need regular intake"},
  {term:"Dietary Guidelines for Americans",def:"Evidence-based nutritional guidance updated every 5 years by USDA and HHS",breakdown:"2020-2025: vary protein, fill half plate with fruits/vegetables, limit added sugars <10%, sodium <2300mg"},
  {term:"MyPlate",def:"USDA food guide replacing Food Pyramid — visual plate divided into fruit, vegetable, grain, protein, dairy",breakdown:"Simple visual guide. Half the plate = fruits and vegetables. Quarter = grains. Quarter = protein"},
  {term:"Processed food continuum",def:"Minimally processed (frozen vegetables) → processed (canned soup) → ultra-processed (chips, soda)",breakdown:"NOVA system: degree of processing predicts health impact better than individual nutrient content"},
  {term:"Inflammation",def:"Immune response to injury or foreign substances — chronic low-grade inflammation links diet to disease",breakdown:"Acute: normal healing. Chronic: drives heart disease, T2DM, cancer, Alzheimer's. Diet affects inflammation"},
  {term:"Gut microbiome",def:"Trillions of bacteria, viruses, fungi living in the digestive tract — vital for health",breakdown:"Affects immunity, mood, metabolism, disease risk. High-fiber diets support diversity. UPF disrupts it"},
  {term:"Food label reading",def:"Understanding nutrition facts panel: serving size, calories, % daily value, ingredient list",breakdown:"Ingredients listed by weight — most to least. First 3 ingredients = bulk of product"},
  {term:"Added sugars on labels",def:"Listed separately since 2020 FDA rule — shows sugars added during processing vs naturally occurring",breakdown:"Natural: fruit (fructose), milk (lactose). Added: sucrose, HFCS, honey, agave in processed foods"},
  {term:"Public health infrastructure",def:"Systems that protect population health: clean water, sanitation, vaccines, surveillance, regulation",breakdown:"Often invisible until it fails. Flint water crisis showed what happens when infrastructure breaks down"},
]);
